409	// blockingResponseWriter runs onWrite once, on the first Write, before
410	// returning. It lets a test stall handleCallback mid-response.
411	type blockingResponseWriter struct {
412		header  http.Header
413		onWrite func()
414		once    sync.Once
415	}
416	
417	func (b *blockingResponseWriter) Header() http.Header { return b.header }
418	func (b *blockingResponseWriter) WriteHeader(int)     {}
419	func (b *blockingResponseWriter) Write(p []byte) (int, error) {
420		b.once.Do(b.onWrite)
421		return len(p), nil
422	}
