424	// TestHandleCallback_SignalsBeforeWritingPage guards the ordering fix for
425	// the timeout/cancel race: the callback outcome must be buffered before the
426	// (potentially blocking) browser-page write, so a write that stalls past
427	// Wait's deadline can't turn a successful redirect into a false timeout. We
428	// stall the handler on its first Write and assert the result is already
429	// buffered at that point — which fails if signal moves back after the write.
430	func TestHandleCallback_SignalsBeforeWritingPage(t *testing.T) {
431		t.Parallel()
432	
433		f := &Flow{state: "s", resultCh: make(chan callbackResult, 1)}
434	
435		writing := make(chan struct{})
436		release := make(chan struct{})
437		w := &blockingResponseWriter{
438			header:  http.Header{},
439			onWrite: func() { close(writing); <-release },
440		}
441		req := httptest.NewRequest(http.MethodGet, "/callback?code=abc&state=s", nil)
442	
443		done := make(chan struct{})
444		go func() {
445			defer close(done)
446			f.handleCallback(w, req)
447		}()
448	
449		<-writing // the handler has reached the browser-page write
450		select {
451		case res := <-f.resultCh:
452			if res.code != "abc" || res.err != nil {
453				t.Fatalf("buffered result = %+v, want code=abc err=nil", res)
454			}
455		default:
456			t.Fatal("result not buffered before the browser-page write")
457		}
458		close(release)
459		<-done
460	}
