478			if strings.Contains(out, f.state) {
479				t.Errorf("%s leaked state: %s", verb, out)
480			}
481		}
482		if got := (*Flow)(nil).String(); got != "<nil>" {
483			t.Errorf("nil Flow String() = %q, want <nil>", got)
484		}
485	}
